mapper.select:
SELECT a.id, a.project_id AS "projectId", a.name, a.arrival_at AS "arrivalAt", a.remark, a.attachments, a.created_by AS "createdBy", a.created_at AS "createdAt", a.updated_by AS "updatedBy", a.updated_at AS "updatedAt", p.code AS "projectCode", p.name AS "projectName", creator.name AS "createdByName" FROM material_arrival a LEFT JOIN project p ON p.id = a.project_id LEFT JOIN sys_account creator ON creator.id = a.created_by
AND a.project_id = #{params.projectId}
AND p.name LIKE CONCAT('%', #{params.projectName}, '%') AND p.name LIKE '%' || #{params.projectName} || '%'
AND a.name LIKE CONCAT('%', #{params.name}, '%') AND a.name LIKE '%' || #{params.name} || '%'
AND a.arrival_at >= #{params.startDate} AND a.arrival_at <= #{params.endDate}
ORDER BY a.arrival_at DESC, a.id DESC
